import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { CreditCard, Users, AlertTriangle, TrendingUp, Calendar, ShoppingCart, DollarSign } from 'lucide-react';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalMes: 0,
    totalEmAberto: 0,
    parcelasFuturas: 0,
    maiorParcelaMes: 0,
    totalGeral: 0,
    qtdComprasMes: 0,
    gastosPorPessoa: {},
    parcelasLista: []
  });

  const hoje = new Date();
  const mesAtual = hoje.getMonth();
  const anoAtual = hoje.getFullYear();

  useEffect(() => {
    async function carregarIndicadores() {
      const { data } = await supabase.from('compras').select('*');

      if (!data) return;

      let totalMes = 0;
      let totalEmAberto = 0;
      let parcelasFuturas = 0;
      let maiorParcelaMes = 0;
      let totalGeral = 0;
      let qtdComprasMes = 0;
      let gastosPorPessoa = {};
      let parcelasLista = [];

      data.forEach(item => {
        const valorTotal = parseFloat(item.valor_total);
        const numParcelas = item.num_parcelas || 1;
        const valorParcela = valorTotal / numParcelas;
        const dataCompra = new Date(item.data_compra);
        const responsavel = item.responsavel || 'Indefinido';

        totalGeral += valorTotal;

        gastosPorPessoa[responsavel] = (gastosPorPessoa[responsavel] || 0) + valorTotal;

        if (dataCompra.getMonth() === mesAtual && dataCompra.getFullYear() === anoAtual) {
          qtdComprasMes++;
        }

        for (let i = 0; i < numParcelas; i++) {
          const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);

          // Parcelas do mês atual
          if (dataParcela.getMonth() === mesAtual && dataParcela.getFullYear() === anoAtual) {
            totalMes += valorParcela;
            if (valorParcela > maiorParcelaMes) {
              maiorParcelaMes = valorParcela;
            }
          }

          // Parcelas futuras
          if (dataParcela >= new Date(anoAtual, mesAtual, 1)) {
            totalEmAberto += valorParcela;
            parcelasFuturas++;
            parcelasLista.push({
              descricao: item.descricao,
              responsavel,
              valor: valorParcela,
              vencimento: dataParcela
            });
          }
        }
      });

      setStats({
        totalMes,
        totalEmAberto,
        parcelasFuturas,
        maiorParcelaMes,
        totalGeral,
        qtdComprasMes,
        gastosPorPessoa,
        parcelasLista
      });
    }

    carregarIndicadores();
  }, []);

  return (
    <div className="fade-in">
      <h2 style={{ marginBottom: '30px' }}>Painel Gerencial</h2>

      {/* GRID PRINCIPAL */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: '20px' }}>

        <Card title="VALOR A PAGAR NO MÊS" icon={<Calendar size={18} />} value={stats.totalMes} color="var(--primary)" />

        <Card title="TOTAL EM ABERTO" icon={<DollarSign size={18} />} value={stats.totalEmAberto} color="#f59e0b" />

        <Card title="PARCELAS FUTURAS" icon={<CreditCard size={18} />} value={stats.parcelasFuturas} isNumber color="#6366f1" />

        <Card title="COMPRAS NO MÊS" icon={<ShoppingCart size={18} />} value={stats.qtdComprasMes} isNumber color="#10b981" />

        <Card title="MAIOR PARCELA DO MÊS" icon={<AlertTriangle size={18} />} value={stats.maiorParcelaMes} color="var(--danger)" />

      </div>

      {/* GASTOS POR PESSOA */}
      <div className="card" style={{ marginTop: '30px' }}>
        <div style={headerCard}><Users size={18} /> GESTÃO POR PESSOA</div>

        {Object.entries(stats.gastosPorPessoa)
          .sort((a, b) => b[1] - a[1])
          .map(([nome, valor]) => (
            <div key={nome} style={rowPessoa}>
              <span>{nome}</span>
              <strong>R$ {valor.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</strong>
            </div>
          ))
        }
      </div>

      {/* PARCELAS EM ABERTO */}
      <div className="card" style={{ marginTop: '30px' }}>
        <div style={headerCard}><CreditCard size={18} /> PARCELAS EM ABERTO</div>

        {stats.parcelasLista.slice(0, 5).map((p, index) => (
          <div key={index} style={rowPessoa}>
            <div>
              <div style={{ fontWeight: 600 }}>{p.descricao}</div>
              <small>{p.responsavel} • {p.vencimento.toLocaleDateString()}</small>
            </div>
            <strong>R$ {p.valor.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</strong>
          </div>
        ))}

        {stats.parcelasLista.length > 5 && (
          <p style={{ marginTop: '10px', fontSize: '0.8rem', opacity: 0.6 }}>
            + {stats.parcelasLista.length - 5} parcelas adicionais...
          </p>
        )}
      </div>

      {/* TOTAL HISTÓRICO */}
      <div className="card" style={{ marginTop: '30px', background: 'linear-gradient(135deg, var(--primary), var(--secondary))', color: 'white' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
          <TrendingUp size={32} />
          <div>
            <span style={{ opacity: 0.8 }}>Total Histórico Lançado</span>
            <h2 style={{ margin: 0 }}>
              R$ {stats.totalGeral.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
            </h2>
          </div>
        </div>
      </div>

    </div>
  );
};

/* COMPONENTE CARD */
const Card = ({ title, icon, value, color, isNumber }) => (
  <div className="card" style={{ borderTop: `4px solid ${color}` }}>
    <div style={headerCard}>{icon} {title}</div>
    <h1 style={valueStyle}>
      {isNumber
        ? value
        : `R$ ${value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`
      }
    </h1>
  </div>
);

/* ESTILOS */
const headerCard = {
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  fontSize: '0.75rem',
  fontWeight: '700',
  letterSpacing: '0.05em',
  opacity: 0.7
};

const valueStyle = {
  fontSize: '2rem',
  margin: '15px 0',
  fontWeight: '700'
};

const rowPessoa = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: '10px 0',
  borderBottom: '1px solid rgba(0,0,0,0.05)'
};

export default Dashboard;
